content:
{
  "sentences": [
    {
      "text": "這家餐廳的牛肉麵沒有那家好吃。",
      "pinyin": "Zhè jiā cāntīng de niúròumiàn méiyǒu nà jiā hǎochī.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 de0 niu2rou4mian4 mei2you3 na4 jia1 hao3chi1",
      "translation_en": "The beef noodles at this restaurant are not as good as those at that restaurant.",
      "translation_ko": "이 식당의 소고기 국수는 저 식당만큼 맛있지 않아요."
    },
    {
      "text": "便利商店的咖啡沒有咖啡店的好喝。",
      "pinyin": "Biànlì shāngdiàn de kāfēi méiyǒu kāfēidiàn de hǎohē.",
      "pinyin_numeric": "bian4li4 shang1dian4 de0 ka1fei1 mei2you3 ka1fei1dian4 de0 hao3he1",
      "translation_en": "The coffee at the convenience store is not as good as the coffee shop's.",
      "translation_ko": "편의점 커피는 커피숍 커피만큼 맛있지 않아요."
    },
    {
      "text": "這個夜市的小吃沒有那個夜市多。",
      "pinyin": "Zhège yèshì de xiǎochī méiyǒu nàge yèshì duō.",
      "pinyin_numeric": "zhe4ge0 ye4shi4 de0 xiao3chi1 mei2you3 na4ge0 ye4shi4 duo1",
      "translation_en": "This night market doesn't have as many snacks as that night market.",
      "translation_ko": "이 야시장은 저 야시장만큼 간식이 많지 않아요."
    },
    {
      "text": "這家店的價格沒有那家店便宜。",
      "pinyin": "Zhè jiā diàn de jiàgé méiyǒu nà jiā diàn piányí.",
      "pinyin_numeric": "zhe4 jia1 dian4 de0 jia4ge2 mei2you3 na4 jia1 dian4 pian2yi2",
      "translation_en": "The prices at this store are not as cheap as those at that store.",
      "translation_ko": "이 가게의 가격은 저 가게만큼 싸지 않아요."
    },
    {
      "text": "坐捷運沒有騎機車方便。",
      "pinyin": "Zuò jiéyùn méiyǒu qí jīchē fāngbiàn.",
      "pinyin_numeric": "zuo4 jie2yun4 mei2you3 qi2 ji1che1 fang1bian4",
      "translation_en": "Taking the MRT is not as convenient as riding a scooter.",
      "translation_ko": "지하철을 타는 것은 오토바이를 타는 것만큼 편리하지 않아요."
    },
    {
      "text": "這家餐廳的服務態度沒有那家好。",
      "pinyin": "Zhè jiā cāntīng de fúwù tàidù méiyǒu nà jiā hǎo.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 de0 fu2wu4 tai4du4 mei2you3 na4 jia1 hao3",
      "translation_en": "The service attitude at this restaurant is not as good as that one.",
      "translation_ko": "이 식당의 서비스 태도는 저 식당만큼 좋지 않아요."
    },
    {
      "text": "這杯紅茶的味道沒有那杯濃。",
      "pinyin": "Zhè bēi hóngchá de wèidào méiyǒu nà bēi nóng.",
      "pinyin_numeric": "zhe4 bei1 hong2cha2 de0 wei4dao4 mei2you3 na4 bei1 nong2",
      "translation_en": "This cup of black tea doesn't have as strong a flavor as that cup.",
      "translation_ko": "이 홍차의 맛은 저 잔만큼 진하지 않아요."
    },
    {
      "text": "這家店的環境沒有那家店安靜。",
      "pinyin": "Zhè jiā diàn de huánjìng méiyǒu nà jiā diàn ānjìng.",
      "pinyin_numeric": "zhe4 jia1 dian4 de0 huan2jing4 mei2you3 na4 jia1 dian4 an1jing4",
      "translation_en": "The atmosphere at this store is not as quiet as that store.",
      "translation_ko": "이 가게의 분위기는 저 가게만큼 조용하지 않아요."
    },
    {
      "text": "這份炒飯的份量沒有那份多。",
      "pinyin": "Zhè fèn chǎofàn de fènliàng méiyǒu nà fèn duō.",
      "pinyin_numeric": "zhe4 fen4 chao3fan4 de0 fen4liang4 mei2you3 na4 fen4 duo1",
      "translation_en": "This serving of fried rice doesn't have as much quantity as that one.",
      "translation_ko": "이 볶음밥의 양은 저 것만큼 많지 않아요."
    },
    {
      "text": "這家店的品質沒有那家店好。",
      "pinyin": "Zhè jiā diàn de pǐnzhì méiyǒu nà jiā diàn hǎo.",
      "pinyin_numeric": "zhe4 jia1 dian4 de0 pin3zhi4 mei2you3 na4 jia1 dian4 hao3",
      "translation_en": "The quality at this store is not as good as that store.",
      "translation_ko": "이 가게의 품질은 저 가게만큼 좋지 않아요."
    }
  ]
}
